INSERT INTO scenes (movie_id, spot_id, image_url, description) VALUES
('b3010b00-c000-0000-0000-000000000001', 'a1010b00-b000-0000-0000-000000000001', 'https://images.unsplash.com/photo-1542044896530-05d85be9b11a?w=800', '주인공 빈센조(송중기)의 아지트이자 금가프라자 상인들과 함께 거대 악당 세력에 맞서 싸우던 메인 무대'),
('b3010b00-c000-0000-0000-000000000002', 'a1010b00-b000-0000-0000-000000000002', 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=800', '박새로이(박서준)와 조이서(김다미)가 남산타워가 보이는 야경을 배경으로 깊은 대화를 나누던 시그니처 장소'),
('b3010b00-c000-0000-0000-000000000003', 'a1010b00-b000-0000-0000-000000000003', 'https://images.unsplash.com/photo-1608778893303-34e89e023fe7?w=800', '순양그룹 진양철 회장(이성민)의 웅장한 저택 ''정심재''의 내부 정원과 고풍스러운 한옥 신들의 배경'),
('b3010b00-c000-0000-0000-000000000004', 'a1010b00-b000-0000-0000-000000000004', 'https://images.unsplash.com/photo-1578894381163-e72c17f2d45f?w=800', '도깨비 김신(공유)과 저승사자(이동욱)가 처음으로 마주치며 스쳐 지나가던 몽환적이고 감성적인 길목'),
('b3010b00-c000-0000-0000-000000000005', 'a1010b00-b000-0000-0000-000000000005', 'https://images.unsplash.com/photo-1601004890684-d8cbf643f5f2?w=800', '기우(최우식)가 친구(박서준)에게 과외 자리를 제안받으며 소주를 마시던 이야기의 시작점이 되는 슈퍼마켓'),
('b3010b00-c000-0000-0000-000000000005', 'a1010b00-b000-0000-0000-000000000006', 'https://images.unsplash.com/photo-1515694346937-94d85e41e6f0?w=800', '폭우가 쏟아지던 밤, 박사장 저택에서 도망쳐 나온 기택(송강호) 가족이 참담한 심정으로 빗속을 뚫고 내려가던 긴 계단'),
('b3010b00-c000-0000-0000-000000000006', 'a1010b00-b000-0000-0000-000000000007', 'https://images.unsplash.com/photo-1534447677768-be436bb09401?w=800', '주인공 최웅(최우식)과 국연수(김다미)의 학창 시절 및 재회 후 복잡 미묘한 감정이 교차하던 골목길과 동네 배경'),
('b3010b00-c000-0000-0000-000000000007', 'a1010b00-b000-0000-0000-000000000008', 'https://images.unsplash.com/photo-1547989453-11e67ffb3885?w=800', '고애신(김태리)과 최유진(이병헌)이 서로의 마음을 확인하고, 의병들의 비밀스러운 활동이 이루어지던 고즈넉한 사찰'),
('b3010b00-c000-0000-0000-000000000008', 'a1010b00-b000-0000-0000-000000000009', 'https://images.unsplash.com/photo-1590579491410-d3df51610e74?w=800', '긴박했던 12·12 군사반란 당시 육군참모총장 공관 및 주요 군사 지휘부의 숨 막히는 대치 상황의 배경'),
('b3010b00-c000-0000-0000-000000000009', 'a1010b00-b000-0000-0000-000000000010', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?w=800', '성기훈(이정재)과 조상우(박해수)가 게임에 참여하기 전, 빚에 쪼들리며 무기력하게 일상을 보내던 생선가게와 동네 시장'),
('b3010b00-c000-0000-0000-000000000010', 'a1010b00-b000-0000-0000-000000000011', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=800', '우영우(박은빈)가 회전문을 통과하기 위해 이준호(강태오)와 함께 ''쿵짝짝'' 왈츠 리듬을 타던 대형 빌딩 로비와 광장'),
('b3010b00-c000-0000-0000-000000000011', 'a1010b00-b000-0000-0000-000000000012', 'https://images.unsplash.com/photo-1540959733332-eab4deceeaf7?w=800', '조선 시대 배경의 좀비 미스터리 속에서 생사초의 비밀이 숨겨져 있고, 궁궐 내 역병이 은밀하게 퍼지던 아름답고도 음산한 연못가'),
('b3010b00-c000-0000-0000-000000000012', 'a1010b00-b000-0000-0000-000000000013', 'https://images.unsplash.com/photo-1506157786151-b8491531f063?w=800', '유전공학자 헬렌 조(수현)의 연구실이자 인공지능 울트론이 닥터 조를 협박해 새로운 신체(비전)를 만들던 최첨단 연구소 외관'),
('b3010b00-c000-0000-0000-000000000013', 'a1010b00-b000-0000-0000-000000000014', 'https://images.unsplash.com/photo-1610569260751-b23b1e872653?w=800', '평화롭던 한강 둔치에 갑작스럽게 정체불명의 괴물이 나타나 시민들을 습격하고 현서(고아성)를 납치해 가던 오프닝 명장면'),
('b3010b00-c000-0000-0000-000000000014', 'a1010b00-b000-0000-0000-000000000015', 'https://images.unsplash.com/photo-1503899036084-c55cdd92da26?w=800', '장만월(이지은)이 운영하는 신비로운 귀신 전용 호텔 ''델루나''의 클래식하고 이국적인 외관 컷의 모티브가 된 레트로 골목'),
('b3010b00-c000-0000-0000-000000000015', 'a1010b00-b000-0000-0000-000000000016', 'https://images.unsplash.com/photo-1548345680-f5475ea5df84?w=800', 'IMF 시대를 살아가는 백이진(남주혁)이 신문 배달을 하거나 나희도(김태리)와 풋풋한 청춘의 고민을 나누던 옛 감성의 언덕길'),
('b3010b00-c000-0000-0000-000000000016', 'a1010b00-b000-0000-0000-000000000017', 'https://images.unsplash.com/photo-1528164344705-47542687000d?w=800', '대학생 승민(이제훈)과 서연(수지)이 숙제를 하기 위해 만나 정답게 이야기를 나누고 첫사랑의 감정을 키워가던 아날로그 감성의 빈집 정원'),
('b3010b00-c000-0000-0000-000000000017', 'a1010b00-b000-0000-0000-000000000018', 'https://images.unsplash.com/photo-1518156677180-95a2893f3e9f?w=800', '도민준(김수현)과 천송이(전지현)가 영원한 사랑을 약속하며 ''사랑의 자물쇠''를 걸고 로맨틱한 데이트를 즐기던 장소'),
('b3010b00-c000-0000-0000-000000000018', 'a1010b00-b000-0000-0000-000000000019', 'https://images.unsplash.com/photo-1577495508048-b635879837f1?w=800', '문동은(송혜교)이 하도영(정성일)의 이목을 끌기 위해 기원을 기웃거리며 대국을 준비하고 치밀한 복수를 설계하던 도심 속 대치 배경'),
('b3010b00-c000-0000-0000-000000000019', 'a1010b00-b000-0000-0000-000000000020', 'https://images.unsplash.com/photo-1481437156560-3205a6a55735?w=800', '재벌 3세 홍해인(김지원)이 대표로 있는 화려한 ''퀸즈 백화점''의 실제 배경으로, 백현우(김수현)와 해인의 일터이자 긴장감 넘치는 비즈니스 신들이 펼쳐진 곳')
