-- 2. Movies 테이블 데이터 추가 (UUID 임의 지정)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, release_year = EXCLUDED.release_year;

-- 3. Spots 테이블 데이터 추가
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, lat = EXCLUDED.lat, lng = EXCLUDED.lng;

-- 4. Scenes 테이블 데이터 추가
ON CONFLICT (movie_id, spot_id) DO NOTHING;
